INSERT INTO texts VALUES(80222045,'勒克納斯的吸雷 布里澤',unistr('通過釋放生命能量，僅在一瞬間綻放光芒的神秘之犬。\u000a據說一旦親眼目睹，那惹人憐愛的姿態便會深印在腦海中，再也無法忘懷。'),'','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100200289,'黑陽龍 伊利歐斯',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡在手牌存在的場合，向對手展示額外牌組的3隻攻擊力3000以上的龍族怪獸可以發動（同名卡最多1張）。此卡特殊召喚。\u000a②：此卡被送去墓地的場合，以我方場上1隻龍族的融合、同步、超量、連結怪獸為對象可以發動（對應這個發動，雙方不能發動效果）。這個回合，對手不能將那隻怪獸作為效果的對象。'),'效果1','效果2','「黑陽龍 伊利歐斯」的效果2適用中','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100200290,'命運的盤上',unistr('這個卡名的卡在1回合只能發動1張。此卡也能向對手展示手牌的1隻通常怪獸，在覆蓋的回合發動。\u000a①：從我方的手牌、墓地將最多5隻通常怪獸攻擊表示特殊召喚。此卡的發動後，直到回合結束時我方不能從額外牌組將怪獸特殊召喚。'),'','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100260001,'小丑戲幫 哈托',unistr('【靈擺效果】\u000a這個卡名的靈擺效果1回合只能使用1次。\u000a①：我方主要階段可以發動。從牌組將靈擺怪獸以外的1張「小丑戲幫」卡片送去墓地，此卡特殊召喚。此效果的發動後，直到下個回合結束前我方不能發動從牌組、額外牌組特殊召喚的怪獸的效果。\u000a【怪獸效果】\u000a①：只要上級召喚的怪獸在我方場上存在，對手場上的怪獸的守備力下降1500。\u000a②：此卡被解放的場合，可以從以下效果選擇1個發動（這個卡名的以下效果1回合各能選擇1次）。\u000a●雙方的額外牌組（表側）、場上的靈擺怪獸全部回到牌組。\u000a●從牌組、額外牌組將靈擺怪獸以外的1隻「小丑戲幫」怪獸無視召喚條件特殊召喚。'),'靈擺效果1','效果2','●回到牌組','●特殊召喚','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261001,'滑稽的黑暗兔寶寶',unistr('①：此卡召喚、特殊召喚時適用。這個回合，我方在通常召喚之外只有1次，在我方主要階段可以召喚1隻記載「卡通世界」的卡名的怪獸。\u000a②：只要場上有「卡通世界」存在，此卡當作卡通怪獸。\u000a③：1回合1次，我方主要階段可以發動。從牌組選1張「卡通」場地、永續魔法卡加入手牌或在我方場上表側表示放置。'),'','召喚（滑稽的黑暗兔寶寶）','效果2','效果3','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261002,'漫畫貓',unistr('這個卡名的②效果1回合只能使用1次。\u000a①：只要場上有「卡通世界」存在，此卡當作卡通怪獸。\u000a②：我方、對手的主要階段可以發動。我方場上1隻怪獸解放，從我方的手牌、牌組將1隻記載「卡通世界」的卡名的怪獸無視召喚條件特殊召喚。我方場上有「卡通世界」存在的場合，解放的怪獸也能從對手場上挑選。'),'','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261003,'邪惡箱',unistr('這個卡名的①效果1回合只能使用1次。\u000a①：我方場上有「卡通世界」存在的場合可以發動。此卡從手牌特殊召喚。那之後，可以適用以下效果。\u000a●從牌組選1張「卡通」陷阱卡加入手牌或在我方場上覆蓋。\u000a②：只要場上有「卡通世界」存在，此卡當作卡通怪獸。\u000a③：我方、對手回合1次，以我方或對手墓地的1張卡為對象可以發動。那張卡回到牌組最下方。'),'效果1','效果3','是否挑選1張陷阱卡？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261004,'暗眼幻像師 無面',unistr('①：可以將此卡從手牌捨棄，從以下效果選擇1個發動（這個卡名的以下效果1回合各能選擇1次）。\u000a●從手牌、牌組將1張「心靈透視眼」在我方場上表側表示放置。\u000a●除了此卡以外，從我方墓地將1隻記載「卡通世界」的卡名的怪獸加入手牌。那之後，可以將那隻怪獸從手牌無視召喚條件特殊召喚。\u000a②：此卡和怪獸進行戰鬥的場合，那2隻不會被那次戰鬥破壞。'),'效果1','●表側表示放置','●從墓地加入手牌','是否特殊召喚？','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261005,'青眼卡通究極龍',unistr('「青眼卡通龍」+卡通怪獸×2\u000a只能讓我方的手牌、場上、墓地的上述卡片回到牌組、額外牌組來特殊召喚。\u000a①：我方的卡通怪獸可以直接攻擊。\u000a②：1回合1次，我方主要階段可以發動。從我方墓地將1張「卡通」卡片或記載那個卡名的卡加入手牌。\u000a③：我方的卡通怪獸被攻擊的傷害計算時可以發動。那隻怪獸直到傷害步驟結束時除外。'),'','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261006,'完美卡通世界',unistr('這個卡名的②效果1回合可以使用最多3次。\u000a①：此卡只要在場地區域存在，卡名當作「卡通世界」。\u000a②：1回合1次，我方主要階段可以發動。從牌組將1張「卡通」卡片或記載那個卡名的卡加入手牌。\u000a③：其他卡發動的效果適用之際，可以將我方場上1隻卡通怪獸直到那個效果處理後除外（這個回合，這個卡名的這個效果不能將原卡名相同的怪獸除外）。'),'','效果2','','是否將1隻怪獸直到效果處理後除外？','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261007,'心靈透視眼',unistr('這個卡名的②效果1回合只能使用1次。\u000a①：只要我方的場上或墓地有「卡通」卡片存在，對手將手牌全部持續公開，我方可以隨時確認對手場上的裡側表示卡。\u000a②：我方的場上、墓地有卡通怪獸以及「卡通」魔法卡存在的場合，宣言1個在同一連鎖上沒有發動效果的卡名可以發動。此卡表側表示存在期間，直到回合結束時原卡名和宣言的卡相同的卡發動的效果無效化。'),'','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261023,'魔女工坊 陶俑魔像',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡在手牌存在的場合，以「魔女工坊 陶俑魔像」以外的我方墓地1張「魔女工坊」卡片為對象可以發動。那張卡加入手牌，此卡特殊召喚。這個回合，我方除了「魔女工坊」怪獸以外不能從額外牌組特殊召喚。\u000a②：我方主要階段可以發動。我方的手牌、場上的怪獸作為融合素材，將1隻「魔女工坊」融合怪獸融合召喚。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261024,'魔女工坊 書籍女巫瑪爾卡',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：將手牌、場上的此卡解放可以發動。從牌組將1張「魔女工坊」場地、永續魔法卡加入手牌。\u000a②：此卡在墓地存在的狀態，我方場上的表側表示的「魔女工坊」怪獸因對手的效果從場上離開的場合可以發動。此卡特殊召喚，將對手場上1隻怪獸解放。此效果特殊召喚的此卡從場上離開的場合被除外。'),'','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261025,'魔女工坊大師 大魔女桑德里永',unistr('「魔女工坊大師 玻璃女巫薇兒」+魔法使族怪獸×2\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：此卡融合召喚的場合可以發動。從手牌、牌組將最多3隻等級7以下的「魔女工坊」怪獸特殊召喚（相同屬性最多1隻）。這個回合，我方除了融合怪獸以外不能從額外牌組特殊召喚。\u000a②：此卡在墓地存在的場合，我方結束階段，向對手展示手牌的1張魔法卡可以發動。此卡守備表示特殊召喚。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261026,'魔女工坊 學徒組',unistr('「魔女工坊」怪獸+魔法使族怪獸\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：我方、對手的主要階段以及戰鬥階段，可以從以下效果選擇1個發動。\u000a●從牌組將1張「魔女工坊」魔法卡加入手牌。\u000a●向對手展示手牌的1張「魔女工坊」通常、速攻魔法卡可以發動。那張魔法卡發動時的效果適用。\u000a②：我方結束階段可以發動。我方的除外狀態的1張「魔女工坊」卡片回到墓地。'),'','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261027,'魔女工坊的慶典',unistr('這個卡名的①②效果1回合只有1次能使用其中1個。\u000a①：可以從以下效果選擇1個發動。\u000a●我方場上1隻「魔女工坊」怪獸和對手場上1張卡破壞。\u000a●我方的墓地、除外狀態的魔法使族怪獸作為融合素材回到牌組，將1隻「魔女工坊」融合怪獸融合召喚。\u000a②：我方結束階段，此卡在墓地存在，我方場上有「魔女工坊」怪獸存在的場合可以發動。此卡加入手牌。'),'效果1','效果2','●破壞效果','●融合召喚','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261028,'魔女工坊的瓦爾普吉斯夜行',unistr('這個卡名的①效果1回合只能使用1次。\u000a①：我方主要階段可以發動。從牌組將1隻「魔女工坊」怪獸加入手牌。那之後，選1張我方的手牌捨棄。\u000a②：我方回合，為了發動我方場上的「魔女工坊」怪獸的效果而將手牌捨棄的場合，可以從牌組將「魔女工坊的瓦爾普吉斯夜行」以外的1張「魔女工坊」魔法、陷阱卡送去墓地作為代替。\u000a\u000a※魔女的聖夜行'),'效果1','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261029,'魔女工坊的消散',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：我方場上有等級5以上的「魔女工坊」怪獸存在，怪獸的效果、魔法、陷阱卡發動時可以發動。那個發動無效並破壞。\u000a②：將不是在這個回合送去墓地的此卡從墓地除外可以發動。從牌組將1隻等級5以上的魔法使族怪獸加入手牌。那之後，選1張我方的手牌捨棄。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261047,'破械式鬼 奢羅',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：我方、對手的主要階段，將此卡從手牌捨棄可以發動。從手牌將1隻惡魔族怪獸特殊召喚。那之後，我方場上1張卡破壞。\u000a②：此卡在墓地存在的狀態，場上的卡被戰鬥或「破械式鬼 奢羅」以外的卡的效果破壞的場合可以發動。此卡加入手牌或特殊召喚。此效果特殊召喚的此卡從場上離開的場合回到牌組最下方。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261048,'破械式鬼 修摩',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡召喚的場合可以發動。除了「破械式鬼 修摩」以外，從牌組將1隻等級4以下的「破械」怪獸特殊召喚。那之後，我方場上1張卡破壞。這個回合，我方除了惡魔族怪獸以外不能特殊召喚。\u000a②：場上的此卡被戰鬥或「破械式鬼 修摩」以外的卡的效果破壞的場合可以發動。從手牌、牌組將「破械式鬼 修摩」以外的1隻「破械」怪獸特殊召喚。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261050,'破械焰魔天 閻魔',unistr('包含「破械神」怪獸的怪獸2隻以上\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：我方結束階段，以這個回合被破壞的我方墓地最多2隻惡魔族怪獸為對象可以發動。那些怪獸特殊召喚。只要此效果特殊召喚的怪獸在我方場上表側表示存在，我方除了惡魔族怪獸以外不能特殊召喚。\u000a②：場上的此卡被戰鬥、效果破壞的場合，可以將我方或對手場上1張表側表示卡破壞作為代替。'),'效果1','','「破械焰魔天 閻魔」的效果特殊召喚','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261051,'破械神雙 羅寂剎',unistr('包含惡魔族怪獸的怪獸2隻以上\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：對手將怪獸表側表示特殊召喚的場合，以其中1隻為對象可以發動。我方場上1隻惡魔族怪獸破壞，作為對象的怪獸的效果直到回合結束時無效。\u000a②：我方場上有連結4以上的「破械」連結怪獸存在，場上的怪獸的效果發動時，將墓地的此卡除外可以發動。那隻發動效果的怪獸破壞。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100261053,'破械習合',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：以包含我方場上的「破械神」連結怪獸的，我方、對手場上2隻表側表示怪獸為對象發動。只用那2隻怪獸為素材進行1隻惡魔族連結怪獸的連結召喚。\u000a②：覆蓋的此卡被效果破壞的場合可以發動。從牌組將1隻「破械」怪獸特殊召喚。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100263001,'黑暗恐獸',unistr('這個卡名的①③效果1回合各能使用1次。\u000a①：魔法卡的效果發動過的回合的我方主要階段可以發動。此卡從手牌特殊召喚。\u000a②：只要對手場上的怪獸全部是守備表示，此卡可以直接攻擊。\u000a③：此卡被送去墓地的場合可以發動。從牌組將1隻等級8以上的恐龍族怪獸加入手牌。對手場上有怪獸存在的場合，隨後可以將加入手牌的那隻怪獸特殊召喚。'),'效果1','效果2','是否特殊召喚？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100263002,'大秘儀之力XII-倒吊人',unistr('這個卡名的①效果1回合只能使用1次。\u000a①：卡的效果發動時，向對手展示手牌的此卡可以發動。從手牌將1隻「大秘儀之力」怪獸守備表示特殊召喚。\u000a②：此卡召喚、反轉召喚、特殊召喚的場合發動。投擲1次硬幣，依照那個正反面適用以下效果。\u000a●正：我方場上1隻怪獸破壞，我方受到那個原攻擊力數值的傷害。\u000a●反：對手場上1隻怪獸破壞，給予對手那個原攻擊力數值的傷害。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100263003,'光幻獸 坎德拉德',unistr('這個卡名的①③效果1回合各能使用1次。\u000a①：此卡在手牌存在的場合，從手牌將2張其他卡捨棄可以發動。此卡特殊召喚。那之後，可以從牌組將1張持有投擲硬幣效果的卡加入手牌。\u000a②：此卡的攻擊力、守備力上升我方的手牌數量×1000。\u000a③：包含從牌組將卡加入手牌效果的魔法、陷阱、怪獸的效果發動時可以發動。那個效果無效。'),'效果1','效果2','是否加入手牌？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100263004,'電漿戰士 艾伊托姆',unistr('這個卡名在規則上也當作「磁石勇士」卡片。此卡不能通常召喚。「電漿戰士 艾伊托姆」只能1回合1次將我方場上1隻等級7以上的怪獸解放，從手牌、墓地特殊召喚。\u000a①：1回合1次，除了「電漿戰士 艾伊托姆」以外，從牌組將1隻「磁石戰士」怪獸或「磁石勇士」怪獸送去墓地可以發動。這個回合，此卡的原攻擊力變成1500，可以直接攻擊。'),'','效果1','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100263005,'白夜騎士團的領主',unistr('這個卡名的①效果1回合只能使用1次。\u000a①：從我方墓地將3隻怪獸除外可以發動。此卡從手牌特殊召喚。那之後，可以從以下效果挑選1個適用。\u000a●從手牌、牌組將1隻「白夜騎士」怪獸特殊召喚。\u000a●從牌組將1張「白之面紗」加入手牌。\u000a②：此卡和對手怪獸進行戰鬥的攻擊宣言時發動。那隻對手怪獸的攻擊力變成0。\u000a③：此卡被對手破壞的場合發動。給予對手1000傷害。'),'效果1','效果2','效果3','都不選擇','●特殊召喚','●加入手牌','','','','','','','','','','');
INSERT INTO texts VALUES(100263006,'不死的死亡領主',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：這個回合已有怪獸被戰鬥破壞的場合，結束階段可以發動。此卡從手牌、墓地特殊召喚。這個回合已有「不死的死亡領主」被戰鬥破壞的場合，此效果特殊召喚的此卡的原攻擊力變成3000，不會被效果破壞。\u000a②：我方主要階段可以發動。依照對手場上的卡片數量+1張，從牌組將包含「一擊必殺！居合抽牌」的卡向對手展示，以喜歡的順序放置在牌組上方。'),'效果1','效果2','請選擇要放置在牌組上方的卡','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100263007,'E.HERO 黏土守衛',unistr('「E.HERO」怪獸+戰士族怪獸\u000a這個卡名的①效果1回合只能使用1次。\u000a①：此卡特殊召喚的場合可以發動。從牌組將1隻「E.HERO」怪獸特殊召喚。對手場上有卡存在的場合，隨後可以給予對手那個數量×400傷害。這個回合，我方除了「HERO」怪獸以外不能從額外牌組特殊召喚。\u000a②：只要此卡在怪獸區域存在，我方場上的其他的「E.HERO」怪獸不會被戰鬥、效果破壞。'),'效果1','是否給予傷害？','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100263008,'人偶鐵鎚',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：以我方場上1隻怪獸為對象可以發動。那隻怪獸破壞，我方抽2張卡。那之後，可以將對手場上1隻怪獸的表示形式變更。\u000a②：此卡在墓地存在的狀態，從我方墓地有怪獸特殊召喚的場合可以發動。此卡加入手牌。'),'效果1','效果2','是否改變表示形式？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100263009,'速攻召喚',unistr('這個卡名的②效果1回合只能使用1次。\u000a①：進行1隻怪獸的通常召喚。那個時候，如果對手場上有怪獸存在，等級5以上的怪獸召喚的場合可以不用解放。\u000a②：我方主要階段，將不是在這個回合送去墓地的此卡從墓地除外可以發動。從我方的牌組、墓地將1隻可以通常召喚的等級5以上的怪獸加入手牌。那之後，進行那1隻怪獸的上級召喚。'),'效果1','效果2','是否改成不用解放來召喚？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100263010,'D-爆發',unistr('這個卡名的卡在1回合只能發動1張。\u000a①：以我方場上1張表側表示的魔法卡為對象可以發動。那張卡破壞，我方抽1張卡。那之後，我方場上有「D-HERO」怪獸存在的場合，可以將我方的手牌、墓地、除外狀態的1隻「D-HERO」怪獸特殊召喚。\u000a②：已裝備裝備卡的怪獸或「D-HERO 教條小子」攻擊的傷害步驟結束時，將墓地的此卡除外可以發動。那隻攻擊怪獸只有1次可以繼續攻擊。'),'效果1','效果2','是否特殊召喚？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100264002,'惡魔的根源',unistr('這個卡名的①②③效果1回合各能使用1次。\u000a①：此卡在手牌存在的場合，將此卡以外的我方的手牌、場上1隻「惡魔」怪獸解放可以發動。此卡特殊召喚。\u000a②：此卡召喚、特殊召喚的場合可以發動。從我方的手牌、牌組、墓地將1隻攻擊力2500的惡魔族、等級6怪獸特殊召喚。\u000a③：我方場上有「惡魔的召喚」存在，對手發動怪獸的效果時可以發動。那個發動無效並破壞。'),'','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(100264003,'魔降雷',unistr('這個卡名在規則上也當作「惡魔」卡片。這個卡名的①②效果1回合各能使用1次。\u000a①：以我方場上1隻「惡魔」怪獸為對象可以發動。那隻怪獸的攻擊力上升600。那之後，可以將對手場上的原攻擊力低於那隻怪獸的攻擊力的怪獸全部破壞。\u000a②：我方主要階段將墓地的此卡除外，以我方墓地1隻攻擊力2500的惡魔族、等級6怪獸為對象可以發動。那隻怪獸加入手牌。'),'','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304081,'電競玩家GG',unistr('等級4機械族怪獸×2\u000a這個卡名的②效果1回合只能使用1次。\u000a①：此卡特殊召喚的場合可以發動。對手場上的怪獸全部變成攻擊表示。\u000a②：對手的場上、墓地有怪獸存在的場合，去除此卡的1個超量素材可以發動。從我方的牌組、額外牌組將1隻機械族怪獸送去墓地。那之後，可以適用以下效果。\u000a●挑選我方墓地1隻機械族超量怪獸，此卡直到結束階段和那隻怪獸當作同名卡。'),'變成攻擊表示','送去墓地','是否改變卡名？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304082,'妖靈龍',unistr('種族、屬性相同且等級不同的怪獸×2\u000a這個卡名的②效果1回合只能使用1次。\u000a①：對手不能將我方場上的融合怪獸作為效果的對象。\u000a②：此卡作為融合召喚的素材送去墓地的場合可以發動。從額外牌組將1隻融合怪獸守備表示特殊召喚。此效果特殊召喚的怪獸效果無效化，在結束階段回到額外牌組。此效果的發動後，直到回合結束時我方除了融合怪獸以外不能從額外牌組特殊召喚。'),'','特殊召喚','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304083,'無明者 陰影',unistr('【靈擺效果】\u000a這個卡名的②靈擺效果1回合只能使用1次。\u000a①：我方除了靈擺怪獸以外不能靈擺召喚。這個效果不會被無效化。\u000a②：攻擊力1000以下的怪獸特殊召喚的場合可以發動。此卡回到手牌。\u000a【怪獸效果】\u000a這個卡名的①②怪獸效果1回合各能使用1次。\u000a①：我方的靈擺區域有卡存在，此卡在手牌存在的場合可以發動。此卡特殊召喚。\u000a②：支付1000生命值可以發動。我方的手牌、場上（表側表示）1張靈擺怪獸卡破壞。那之後，可以從牌組將1隻靈擺怪獸表側加入額外牌組。'),'','此卡回到手牌','此卡特殊召喚','破壞','是否將1張卡加入額外牌組？','請選擇加入額外牌組的卡','','','','','','','','','','');
INSERT INTO texts VALUES(101304084,'貴賓鯨魚',unistr('①：此卡可以解放任意數量的怪獸來表側表示上級召喚。\u000a②：此卡上級召喚的場合可以發動。依照為了此卡的上級召喚而解放的怪獸數量，給此卡放置貴賓計數器。\u000a③：對手發動卡的效果時，去除此卡的1個貴賓計數器可以發動。投擲1次硬幣，並猜正反面。如果猜對，那個效果無效。如果猜錯，此卡的原攻擊力直到回合結束時變成一半。'),'解放任意數量的怪獸召喚','放置計數器','投擲硬幣','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304085,'戒指的魔靈',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡在手牌存在的場合，以場上1隻表側表示怪獸為對象可以發動。此卡特殊召喚，對象怪獸變成魔法使族，這個回合只有1次不會被效果破壞。這個回合，我方除了魔法使族怪獸以外不能從額外牌組特殊召喚。\u000a②：此卡為了發動魔法使族怪獸的效果而被解放或除外的場合可以發動。此卡加入手牌。'),'特殊召喚','此卡加入手牌','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304086,'檢查機',unistr('我方場上有怪獸存在的場合，此卡不能召喚。\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：將此卡解放可以發動。從牌組將1隻攻擊力和守備力數值相同的機械族怪獸特殊召喚。此效果特殊召喚的怪獸在結束階段回到手牌。\u000a②：將墓地的此卡除外，捨棄1張手牌可以發動。在我方場上將1隻「碎鐵片衍生物」（機械族、地、等級1、攻/守0）特殊召喚。這個衍生物不能作為融合、同步、連結召喚的素材。'),'','特殊召喚','特殊召喚衍生物','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304087,'鏽蝕猛瑪',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡在手牌存在的場合，從額外牌組將連結標記合計是5的機械族連結怪獸除外可以發動。此卡特殊召喚。\u000a②：以我方、對手場上的卡各1張為對象可以發動。那些卡回到手牌。此卡和連結3以上的機械族連結怪獸是連結狀態的場合，此效果在對手回合也能發動。'),'特殊召喚','回到手牌','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304088,'主祭的空想',unistr('這個卡名的①②③效果1回合各能使用1次。\u000a①：此卡在手牌存在的場合，從手牌將1張其他卡捨棄可以發動。此卡特殊召喚。\u000a②：此卡在墓地存在的狀態，超量怪獸被送去墓地的場合，將此卡除外可以發動。從我方墓地將1隻不死族怪獸特殊召喚。\u000a③：此卡被除外的下個回合的準備階段，以我方場上1隻不死族超量怪獸為對象可以發動。除外狀態的此卡作為那隻怪獸的超量素材。'),'特殊召喚','從墓地特殊召喚','作為超量素材','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304089,'末日的主祭 薩繆爾',unistr('等級6怪獸×2\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：我方、對手的主要階段，去除此卡的1個超量素材，以我方墓地1隻不死族怪獸為對象可以發動。那隻怪獸特殊召喚。那之後，可以將對手場上1隻攻擊力在那隻怪獸的攻擊力以下的怪獸的效果無效化。\u000a②：此卡被送去墓地的場合，以我方、對手的墓地1隻怪獸為對象可以發動。那隻怪獸回到牌組。'),'特殊召喚','回到牌組','是否將1隻怪獸的效果無效？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304090,'GMX夥伴 瑟蘭德亞',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：向對手展示手牌的此卡可以發動。從手牌將1隻「GMX」怪獸或恐龍族怪獸特殊召喚。這個回合，我方只能用「GMX」怪獸直接攻擊。\u000a②：此卡被怪獸的效果特殊召喚的場合可以發動。我方的手牌、墓地、除外狀態的1隻等級4以下的「GMX」怪獸或恐龍族怪獸守備表示特殊召喚。'),'從手牌特殊召喚','守備表示特殊召喚','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304091,'GMX鎮壓小隊',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡在手牌存在，我方場上有「GMX」怪獸或恐龍族怪獸存在的場合可以發動。此卡特殊召喚。\u000a②：以場上1隻表側表示怪獸為對象可以發動。從我方牌組上方翻開卡片，直到恐龍族怪獸出現為止，那隻恐龍族怪獸送去墓地，對象怪獸直到回合結束時變成恐龍族。剩下的卡回到牌組。'),'特殊召喚','翻卡','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304092,'進化的丹寧',unistr('「回歸恐龍 丹寧」+恐龍族怪獸\u000a這個卡名的①效果1回合只能使用1次。\u000a①：此卡特殊召喚的場合可以發動。從牌組將1張「GMX」卡片加入手牌。\u000a②：我方用「GMX」卡片的效果將卡翻開的場合，可以依照此卡在何處存在發動以下效果（這個卡名的以下效果1回合各能使用1次）。\u000a●場上：我方回復1500生命值。\u000a●墓地：此卡特殊召喚。'),'檢索','選擇效果','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304093,'GMX-複合暴龍',unistr('「GMX」怪獸+恐龍族怪獸2隻以上\u000a①：此卡依照作為此卡的融合素材的恐龍族怪獸數量得到以下效果。\u000a●3隻以上：對手不能將此卡作為效果的對象。\u000a●4隻以上：此卡在1次戰鬥階段中可以攻擊3次。\u000a●5隻以上：每次對手將怪獸召喚、特殊召喚，對手失去800生命值。\u000a②：1回合1次，我方用「GMX」卡片的效果將卡翻開的場合可以發動。場上的其他怪獸全部破壞。'),'','破壞怪獸','●3隻以上','●4隻以上','●5隻以上','','','','','','','','','','','');
INSERT INTO texts VALUES(101304094,'GMX第55次實驗報告',unistr('這個卡名的①②效果1回合只有1次能使用其中1個。\u000a①：我方的手牌、場上的怪獸作為融合素材，將1隻恐龍族融合怪獸融合召喚。對手場上有怪獸存在的場合，我方牌組的「GMX」怪獸也能有最多1隻作為融合素材。\u000a②：我方主要階段將墓地的此卡除外可以發動。從我方牌組上方翻開卡片，直到「GMX」卡片出現為止，那張「GMX」卡片加入手牌。剩下的卡回到牌組。'),'融合召喚','翻卡','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304095,'GMX第5號實驗室',unistr('這個卡名的②效果1回合只能使用1次。\u000a①：在我方將「GMX」怪獸召喚、特殊召喚成功時，對手不能發動效果。\u000a②：我方主要階段可以發動。從牌組將「GMX第5號實驗室」以外的1張「GMX」魔法、陷阱卡在我方場上覆蓋。那之後，選1張手牌放置在牌組最上方。'),'','從牌組覆蓋','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304096,'反GMX最終實驗',unistr('我方場上有「GMX」怪獸存在的場合可以發動此卡。\u000a①：1回合1次，對手在場上發動怪獸的效果時可以發動。從牌組上方翻開5張卡，其中有「GMX」卡片的場合，那個發動的效果無效。翻開的卡以喜歡的順序回到牌組上方或下方。'),'翻卡','回到牌組上方','回到牌組下方','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101304186,'碎鐵片衍生物','由「檢查機」的效果特殊召喚。這個衍生物不能作為融合、同步、連結召喚的素材。','','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305001,'超魔劍士 黑混沌',unistr('此卡不能通常召喚。「超魔劍士 黑混沌」只能1回合1次從我方的手牌、墓地讓1隻魔法使族、戰士族儀式怪獸回到牌組來特殊召喚。\u000a①：將此卡從手牌捨棄可以發動。從我方的牌組、墓地將1張記載「光與闇的儀式」的卡名的永續陷阱卡在我方場上表側表示放置。\u000a②：只要我方墓地有儀式魔法卡存在，此卡不受對手發動的效果影響。\u000a③：1回合1次，我方主要階段可以發動。對手場上2張卡除外。'),'效果1','效果3','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305002,'混沌的魔王-骷髏惡魔',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡在手牌、墓地存在的場合，除了此卡以外，以包含記載「光與闇的儀式」的卡名的卡的我方、對手的墓地、除外狀態（表側）的卡合計3張為對象可以發動。那些卡以喜歡的順序回到牌組下方，此卡特殊召喚。\u000a②：此卡被送去墓地的場合，從手牌、牌組將1張儀式魔法卡送去墓地可以發動。從牌組將1隻在那張卡有記載卡名的儀式怪獸加入手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305003,'精靈聖賢者',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡召喚、特殊召喚的場合可以發動。我方的手牌全部向對手展示。其中有記載「光與闇的儀式」的卡名的卡的場合，可以讓我方抽3張卡。抽牌的場合，隨後選2張我方的手牌捨棄。此效果的發動後，直到回合結束時我方只能從額外牌組將怪獸特殊召喚1次。\u000a②：將此卡解放可以發動。從手牌將1隻記載「光與闇的儀式」的卡名的儀式怪獸特殊召喚。'),'效果1','效果2','是否抽3張卡？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305004,'栗球獸衛',unistr('這個卡名的①效果1回合只能使用1次。\u000a①：我方、對手回合，可以將此卡從手牌捨棄，從以下效果選擇1個發動。\u000a●這個回合，我方受到的戰鬥、效果傷害只有1次變成0。\u000a●從牌組將1張記載「光與闇的儀式」的卡名的速攻魔法、陷阱卡在我方場上覆蓋。此效果覆蓋的卡在覆蓋的回合也能發動。\u000a②：等級8儀式怪獸1隻儀式召喚的場合，可以使用1張此卡作為儀式召喚所需的解放。'),'效果1','●傷害變成0','●覆蓋魔法、陷阱卡','適用「栗球獸衛」的效果來發動','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305005,'劫火之三幻魔-神炎皇 烏利亞',unistr('此卡不能通常召喚，只能用「三幻魔」卡片的效果特殊召喚。這個卡名的①效果1回合只能使用1次。\u000a①：向對手展示手牌的此卡可以發動。從牌組將1張「三幻魔」陷阱卡加入手牌。那之後，選1張我方的手牌捨棄。\u000a②：此卡的攻擊力、守備力上升雙方墓地的陷阱卡數量×1000。\u000a③：我方、對手回合1次，以場上1張魔法、陷阱卡為對象可以發動（應對這個發動，雙方不能發動效果）。那張卡破壞。'),'效果1','效果3','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305006,'罪禍之三幻魔-降雷皇 哈蒙',unistr('此卡不能通常召喚，只能用「三幻魔」卡片的效果特殊召喚。這個卡名的①效果1回合只能使用1次。\u000a①：向對手展示手牌的此卡可以發動。從牌組將1張「三幻魔」魔法卡加入手牌。那之後，選1張我方的手牌捨棄。\u000a②：1回合1次，怪獸被送去對手墓地的場合發動。給予對手1000傷害。\u000a③：此卡被戰鬥、效果破壞的場合可以發動。這個回合，我方受到的全部傷害變成0。'),'效果1','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305007,'無窮之三幻魔-幻魔皇 拉比艾爾',unistr('此卡不能通常召喚，只能用「三幻魔」卡片的效果特殊召喚。這個卡名的①效果1回合只能使用1次。\u000a①：向對手展示手牌的此卡可以發動。從牌組將「無窮之三幻魔-幻魔皇 拉比艾爾」以外的1隻「三幻魔」怪獸加入手牌。那之後，選1張我方的手牌捨棄。\u000a②：我方、對手回合1次，將我方場上2隻其他的「三幻魔」怪獸解放可以發動。對手場上的怪獸全部破壞，此卡的攻擊力上升破壞的數量×1000。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305008,'三幻魔的操世者',unistr('這個卡名的①②③效果1回合各能使用1次。\u000a①：向對手展示手牌的此卡可以發動。選1張我方的手牌捨棄，從手牌將等級8以外的1隻「三幻魔」怪獸守備表示特殊召喚。\u000a②：捨棄1張手牌可以發動。除了捨棄的卡以外，從我方的手牌、墓地將等級8以外的1隻「三幻魔」怪獸守備表示特殊召喚。\u000a③：將墓地的此卡除外可以發動。從我方墓地將等級8以外的1隻「三幻魔」怪獸守備表示特殊召喚。'),'效果1','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305009,'三幻魔的殉教者',unistr('這個卡名的①②③效果1回合各能使用1次。\u000a①：此卡召喚、特殊召喚的場合可以發動。從牌組將1張「三幻魔」場地魔法、永續魔法、永續陷阱卡在我方場上表側表示放置。\u000a②：我方場上有其他的「三幻魔」怪獸存在的場合可以發動。從我方的手牌、牌組、墓地將2隻「三幻魔的殉教者」特殊召喚。\u000a③：對手結束階段，我方墓地有此卡和等級10的「三幻魔」怪獸存在的場合可以發動。此卡加入手牌。'),'效果1','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305010,'威斯卡・雷盟',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：我方的「雷盟」卡片的效果已破壞卡片的我方、對手回合，向對手展示手牌的此卡可以發動。從手牌將最多3隻雷族怪獸特殊召喚。那之後，最多到那個數量，可以將場上的卡破壞。這個回合，我方不能從手牌以外將效果怪獸特殊召喚。\u000a②：在手牌以外有怪獸的效果發動時，讓我方場上1隻其他的雷族怪獸回到手牌可以發動。那個發動無效並破壞。'),'效果1','效果2','是否將場上的卡破壞？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305011,'薩吉・雷盟',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：向對手展示手牌的此卡，以場上1隻怪獸為對象可以發動。那隻怪獸破壞，從手牌將1隻雷族怪獸特殊召喚。這個回合，我方不能從手牌以外將效果怪獸特殊召喚。\u000a②：此卡在怪獸區域存在的狀態，此卡以外的卡被效果破壞的場合可以發動。從牌組將「薩吉・雷盟」以外的1隻「雷盟」怪獸加入手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305012,'克拉克・雷盟',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：對手回合，對手發動場上的怪獸的效果時，向對手展示手牌的此卡可以發動。那隻怪獸破壞，從手牌將1隻雷族怪獸特殊召喚。這個回合，我方不能從手牌以外將效果怪獸特殊召喚。\u000a②：此卡在怪獸區域存在的狀態，此卡以外的卡被效果破壞的場合可以發動。從牌組將1張「雷盟」魔法、陷阱卡送去墓地。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305013,'格瑞恩・雷盟',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：向對手展示手牌的此卡，以場上1張魔法、陷阱卡為對象可以發動。那張卡破壞，從手牌將1隻雷族怪獸特殊召喚。這個回合，我方不能從手牌以外將效果怪獸特殊召喚。\u000a②：此卡在怪獸區域存在的狀態，此卡以外的卡被效果破壞的場合可以發動。從牌組將1張「雷盟」魔法卡或「天空城塞 庫龍」加入手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305014,'艾米・雷盟',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡用抽卡以外的方法加入手牌的場合，向對手展示此卡，以場上1張卡為對象可以發動。那張卡破壞，從手牌將1隻雷族怪獸特殊召喚。這個回合，我方不能從手牌以外將效果怪獸特殊召喚。\u000a②：此卡在怪獸區域存在的狀態，此卡以外的卡被效果破壞的場合可以發動。從牌組將1張「雷盟」陷阱卡加入手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305015,'追憶之阿萊斯特',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡在手牌存在的場合，以場上1隻魔法使族怪獸或融合怪獸為對象可以發動。此卡特殊召喚，對象怪獸的攻擊力直到回合結束時上升1000。\u000a②：此卡召喚、特殊召喚、反轉的場合，從額外牌組將1隻「召喚獸」怪獸除外可以發動。從牌組將1張「召喚魔術」或記載那個卡名的魔法卡加入手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305016,'法之神靈 愛華斯',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：將手牌、場上的此卡除外可以發動。從牌組將1隻「阿萊斯特」怪獸加入手牌。在場上發動的場合，隨後可以進行1隻魔法使族怪獸的召喚。\u000a②：此卡在墓地存在的狀態，我方場上的表側表示的融合怪獸因戰鬥以外被送去墓地的場合可以發動。此卡特殊召喚。那之後，可以將我方的手牌、場上的怪獸作為融合素材，將1隻「召喚獸」怪獸融合召喚。'),'效果1','效果2','是否進行召喚？','是否融合召喚？','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305017,'人工神靈 薇拉卡姆',unistr('這個卡名的①②③效果1回合各能使用1次。\u000a①：我方的場上或墓地有「阿萊斯特」怪獸存在的場合可以發動。此卡從手牌特殊召喚。\u000a②：此卡特殊召喚的場合可以發動。從牌組將1張「召喚魔術」或記載那個卡名的魔法卡在我方場上覆蓋。\u000a③：對手連鎖我方的融合怪獸的效果的發動，來發動卡的效果時可以發動。場上的此卡除外，那個對手的效果無效並除外。'),'效果1','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305018,'魅影騎士團 凋零披風',unistr('這個卡名的①②③效果1回合各能使用1次。\u000a①：此卡在手牌存在的場合，向對手展示手牌1張其他的「魅影騎士團」卡片可以發動。此卡特殊召喚。\u000a②：此卡召喚、特殊召喚的場合可以發動。從牌組將1隻「魅影騎士團」怪獸加入手牌。\u000a③：將墓地的此卡除外，以我方場上1隻超量怪獸為對象可以發動。那隻超量怪獸在這個回合可以作為和自身的階級相同數值的等級的怪獸成為超量召喚的素材。'),'效果1','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305019,'魅影騎士團 厄運鐵靴',unistr('這個卡名的①方法的特殊召喚1回合只能有1次，②③效果1回合各能使用1次。\u000a①：我方場上沒有怪獸存在的場合，此卡可以從手牌特殊召喚。\u000a②：此卡召喚、特殊召喚的場合可以發動。從牌組將1張「魅影騎士團」魔法、陷阱卡在我方場上覆蓋。\u000a③：將墓地的此卡除外，以我方場上的最多2隻等級3、階級3的闇屬性怪獸為對象可以發動。那些怪獸的等級、階級上升1。'),'特殊召喚','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305020,'S-Force 白天鵝',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡召喚、特殊召喚的場合可以發動。從牌組將「S-Force 白天鵝」以外的1隻「S-Force」怪獸加入手牌。此卡的正前方有對手怪獸存在的場合，隨後我方可以抽1張卡。\u000a②：我方場上的怪獸的正前方的對手怪獸發動效果的場合可以發動。我方場上的全部「S-Force」怪獸的攻擊力上升1000。'),'效果1','效果2','是否抽1張卡？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305021,'童話動物 小兔好朋友',unistr('這個卡名的①②效果1回合只能使用其中1個。\u000a①：對手將怪獸召喚、特殊召喚的場合可以發動。此卡從手牌特殊召喚。那之後，可以將我方的手牌、場上的怪獸作為融合素材，將1隻「童話動物」融合怪獸融合召喚。\u000a②：此卡召喚、特殊召喚的場合可以發動。從牌組將1隻「童話動物」怪獸加入手牌。此效果將通常怪獸加入手牌的場合，隨後可以從手牌將任意數量的獸族怪獸特殊召喚。'),'效果1','效果2','是否融合召喚？','是否特殊召喚？','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305022,'原初之神 法拉',unistr('這個卡名的①②③效果1回合各能使用1次。\u000a①：向對手展示手牌的此卡和手牌的1張魔法、陷阱卡可以發動。直到下個回合結束時，應對展示的魔法、陷阱卡以及那些同名卡的效果的發動，雙方不能發動效果。\u000a②：此卡被魔法、陷阱卡的效果從手牌、場上送去墓地的場合可以發動。此卡特殊召喚。\u000a③：此卡從墓地特殊召喚的場合可以發動。得到對手場上的攻擊力最高的1隻怪獸的控制權。'),'效果1','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305023,'繫星之雷后',unistr('這個卡名的①方法的特殊召喚1回合只能有1次，②③效果1回合各能使用1次。\u000a①：此卡可以讓我方場上最多2隻怪獸回到手牌，從手牌特殊召喚。\u000a②：此卡特殊召喚的場合，向對手展示手牌任意數量的怪獸（相同等級最多1隻），以那個數量的對手場上的表側表示卡為對象可以發動。那些卡的效果無效。\u000a③：場上的此卡被效果破壞送去墓地的場合可以發動。此卡加入手牌。'),'','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305024,'沼地的魔道王',unistr('這個卡名的效果1回合只能使用1次。\u000a①：此卡在手牌存在的場合可以發動。向對手展示額外牌組的1隻融合怪獸，從牌組將1隻在那隻怪獸有記載卡名的融合素材怪獸除外。那之後，此卡特殊召喚。這個回合，此效果特殊召喚的此卡作為融合素材的場合，可以當作此效果除外的怪獸的同名卡。'),'效果1','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305025,'薄明之魔 雷拉曙',unistr('【靈擺效果】\u000a這個卡名的靈擺效果1回合只能使用1次。\u000a①：我方場上的靈擺怪獸被對手的效果破壞的場合，可以將此卡破壞，作為其中1隻被破壞的靈擺怪獸的代替。\u000a【怪獸效果】\u000a這個卡名的①②怪獸效果1回合各能使用1次。\u000a①：此卡在手牌存在的場合，以我方場上1隻靈擺怪獸為對象可以發動。那隻靈擺怪獸在我方的靈擺區域放置，此卡特殊召喚。此效果在靈擺區域放置的卡的靈擺效果在這個回合不能發動。\u000a②：我方、對手回合，將此卡解放，以我方的靈擺區域1張卡為對象可以發動。這個回合，那張卡不會被對手的效果破壞。'),'','效果1','效果2','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305026,'灰層',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：將此卡解放，向對手展示手牌的1隻機械族怪獸可以發動。從牌組將和展示的怪獸屬性不同的1隻機械族怪獸加入手牌。此效果將攻擊力1200以下的怪獸加入手牌的場合，隨後可以從手牌將1隻機械族怪獸特殊召喚。\u000a②：此卡在墓地存在的狀態，我方怪獸被效果破壞的場合，將此卡除外可以發動。場上1張卡破壞。'),'效果1','效果2','是否特殊召喚？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305027,'黑色混沌的魔術師 黑混沌',unistr('藉由「光與闇的儀式」降臨\u000a這個卡名的①③效果1回合各能使用1次。\u000a①：此卡特殊召喚的場合可以發動。從我方墓地將1張魔法卡加入手牌。\u000a②：只要此卡在怪獸區域存在，我方場上的魔法、陷阱卡不會被對手的效果破壞，不能被對手的效果除外，除了以此卡為對象的效果以外，此卡不受對手發動的效果影響。\u000a③：以對手場上1張卡為對象可以發動。那張卡裡側除外。'),'效果1','效果3','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305028,'光與闇的戰士 混沌士兵',unistr('藉由「光與闇的儀式」降臨\u000a這個卡名的①③效果1回合各能使用1次。\u000a①：此卡特殊召喚的場合，以對手場上1張卡為對象可以發動。那張卡除外。\u000a②：只要此卡在怪獸區域存在，此卡不會被戰鬥破壞，除了以此卡為對象的效果以外，此卡不受對手發動的效果影響。\u000a③：此卡戰鬥破壞對手怪獸時可以發動。此卡的攻擊力上升1500，只有1次可以繼續攻擊。'),'效果1','效果3','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305029,'混沌的三幻魔',unistr('不能通常召喚的等級10怪獸×3\u000a「混沌的三幻魔」只能1回合1次用融合召喚或以下方法特殊召喚。\u000a●將我方場上的上述卡片送去墓地，可以從額外牌組特殊召喚。\u000a①：場上的此卡1回合最多2次不會被效果破壞。\u000a②：我方、對手回合最多3次，以對手場上1隻表側表示怪獸為對象可以發動（同一連鎖上最多1次）。那隻怪獸的效果直到回合結束時無效。那之後，可以讓我方的生命值回復那個攻擊力的一半數值。'),'效果2','是否回復生命值？','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305030,'召喚獸 索拉特',unistr('「阿萊斯特」怪獸+炎、風屬性怪獸\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：我方、對手的主要階段，以我方或對手的墓地1隻等級6以下的怪獸為對象可以發動。那隻怪獸在我方場上守備表示特殊召喚。此效果特殊召喚的怪獸的效果無效化。\u000a②：此卡在墓地存在的場合可以發動。包含墓地的此卡的我方的場上、墓地的怪獸作為融合素材除外，將1隻「召喚獸」融合怪獸融合召喚。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305031,'召喚獸 貝巴隆',unistr('「阿萊斯特」怪獸+光、地屬性怪獸\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：此卡特殊召喚的場合可以發動。從牌組將1隻「人工神靈 薇拉卡姆」或1張「魔法名-「新世界的開始」」加入手牌。那之後，可以從我方或對手的墓地將1隻怪獸除外。\u000a②：將墓地的此卡除外，以我方場上1隻融合怪獸為對象可以發動。對手場上的全部怪獸的攻擊力直到回合結束時下降對象怪獸的攻擊力數值。'),'效果1','效果2','是否將1隻怪獸除外？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305032,'召喚獸 俄刻阿諾斯',unistr('「阿萊斯特」怪獸+闇、水屬性怪獸\u000a這個卡名的③效果1回合只能使用1次。\u000a①：只要此卡在主要怪獸區域存在，對手怪獸不能選擇其他怪獸作為攻擊對象。\u000a②：只要此卡在額外怪獸區域存在，送去對手墓地的怪獸不去墓地而是除外。\u000a③：將墓地的此卡除外，以我方場上1隻融合怪獸為對象可以發動。這個回合，那隻怪獸可以直接攻擊。'),'','效果3','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305033,'超越召喚獸 埃翁',unistr('屬性不同的融合怪獸×2隻以上\u000a這個卡名的①②效果1回合只有1次能使用其中1個。\u000a①：此卡融合召喚的場合可以發動。最多到那些作為融合素材的怪獸數量，將我方、對手的場上、墓地的卡除外。3隻以上作為素材的場合，隨後可以確認對手的額外牌組，從其中將最多3張除外。\u000a②：我方、對手回合，宣言1個屬性可以發動。此卡以外的場上的全部怪獸直到回合結束時變成宣言的屬性。'),'效果1','效果2','是否確認對手的額外牌組？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305034,'怦然期待的童話動物家族',unistr('「童話動物」怪獸+獸族怪獸\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：此卡融合召喚的場合，以我方場上的「童話動物」卡片和對手場上的卡各自相同數量為對象可以發動。那些卡回到手牌。\u000a②：對手將怪獸召喚、特殊召喚的場合，或此卡被選擇作為對手怪獸的攻擊對象的場合，以我方墓地1隻獸族怪獸為對象可以發動。此卡的等級下降2，對象怪獸特殊召喚。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305035,'榮耀聖潔之詩-妖精頌歌',unistr('協調+協調以外的魔法使族怪獸1隻\u000a這個卡名的②效果1回合只能使用1次。\u000a①：只要此卡在中央的主要怪獸區域存在，雙方除了用中央的主要怪獸區域的怪獸以外不能攻擊宣言。\u000a②：此卡在中央的主要怪獸區域存在的場合，我方、對手的主要階段可以發動。此卡回到額外牌組，從我方的手牌、牌組、墓地各將最多1隻「耀聖」怪獸特殊召喚。'),'效果2','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305036,'無現壞收 無之獲取者',unistr('協調+協調以外的怪獸1隻以上\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：此卡同步召喚的場合可以發動。從牌組將1隻等級8以上且攻擊力0的怪獸加入手牌。\u000a②：以我方墓地1隻攻擊力0的怪獸為對象可以發動。那隻怪獸特殊召喚。此效果特殊召喚的怪獸的效果無效化，不能作為融合、同步、超量、連結召喚的素材。'),'效果1','效果2','「無現壞收 無之獲取者」的效果特殊召喚','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305037,'魅影騎士團 惡念鐮刀',unistr('闇屬性等級3怪獸×2\u000a這個卡名的①②③效果1回合各能使用1次。\u000a①：去除此卡的1個超量素材可以發動。從牌組將1隻「魅影騎士團」怪獸特殊召喚。\u000a②：此卡在怪獸區域存在的狀態，我方將「超量龍」怪獸超量召喚的場合可以發動。從牌組將1張「升階魔法」魔法卡加入手牌。\u000a③：此卡被破壞的場合可以發動。超量怪獸以外的我方的除外狀態的1張「魅影騎士團」卡片加入手牌。'),'效果1','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305038,'童話動物教母 媽咪',unistr('獸族等級2怪獸×3隻以上\u000a「童話動物教母 媽咪」1回合1次也能重疊在我方場上的「童話動物 媽咪」上方來超量召喚。\u000a①：此卡特殊召喚的場合可以發動。從我方的牌組、墓地將1張「童話動物」魔法、陷阱卡加入手牌。\u000a②：此卡的攻擊力上升作為此卡作為超量素材持有的「童話動物」怪獸的攻擊力、守備力的合計數值。\u000a③：去除此卡的5個超量素材可以發動。對手場上的卡全部回到手牌。'),'是否重疊在「童話動物 媽咪」上方來超量召喚？','效果1','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305039,'無垢祈禱的獄神使',unistr('連結怪獸以外的怪獸2隻\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：此卡連結召喚的場合，如果我方墓地有「獄神」怪獸存在可以發動。從牌組將1張「預幻」卡片加入手牌。\u000a②：我方、對手的主要階段，我方場上有其他的天使族、闇屬性怪獸存在的場合可以發動。用包含此卡的我方場上的怪獸為素材進行連結召喚。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305040,'S-Force 黑夜屠殺者',unistr('包含「S-Force」怪獸的怪獸2隻\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：此卡特殊召喚的場合可以發動。從牌組將1張「S-Force」魔法、陷阱卡加入手牌。\u000a②：我方、對手回合，將場上的此卡和手牌的1張「S-Force」卡片除外可以發動。從牌組、額外牌組將「S-Force 黑夜屠殺者」以外的1隻「S-Force」怪獸特殊召喚。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305041,'S-Force 亂名者',unistr('包含「S-Force」怪獸的怪獸2隻以上\u000a這個卡名的②效果1回合只能使用1次。\u000a①：只要此卡的正前方有對手怪獸存在，對手不能將此卡作為效果的對象，不能用怪獸發動的效果將怪獸特殊召喚。\u000a②：我方、對手回合，以場上1隻怪獸為對象可以發動。那隻怪獸的位置向那個控制者的其他的主要怪獸區域移動。'),'效果2','請選擇移動位置的怪獸','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305042,'小丑戲幫 朵莉詩',unistr('儀式、融合、同步、超量、靈擺怪獸2隻\u000a①：上級召喚的我方怪獸在1次戰鬥階段中可以攻擊2次。\u000a②：此卡被解放的場合，可以從以下效果選擇1個發動（這個卡名的以下效果1回合各能選擇1次）。\u000a●雙方的場上、墓地的連結怪獸全部回到額外牌組。\u000a●雙方讓自身的手牌全部回到牌組。那之後，雙方依照回去的數量抽牌。'),'效果2','●回到牌組','●抽牌','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305043,'禪那乃追儺戲姬',unistr('效果怪獸2隻以上\u000a此卡連結召喚的場合，手牌的1隻怪獸也能作為連結素材。\u000a這個卡名的①②效果1回合各能使用1次。\u000a①：此卡連結召喚的場合可以發動。從牌組將1隻怪獸送去墓地。只用我方場上的怪獸為素材連結召喚的場合，送去墓地的怪獸也能從額外牌組挑選。\u000a②：此卡從場上被送去墓地的場合，下個我方準備階段可以發動。從我方墓地將1隻怪獸加入手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305044,'光與闇的儀式',unistr('這個卡名的②效果1回合只能使用1次。\u000a①：解放我方的手牌、場上的怪獸，或將我方墓地的怪獸除外來代替解放，直到等級合計為儀式召喚的怪獸的等級以上為止，從手牌儀式召喚1隻「黑色混沌的魔術師 黑混沌」或「光與闇的戰士 混沌士兵」。\u000a②：此卡在墓地存在的場合可以發動。從我方墓地將1張記載「光與闇的儀式」的卡名的卡和此卡加入手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305045,'混沌魔術箱',unistr('①：對手發動以我方場上的其他卡為對象的效果時可以發動。那些我方的卡其中1張回到手牌（裡側表示卡則翻開確認），場上1張卡破壞。那之後，可以從手牌將卡名和回到手牌的卡不同的，1隻記載「光與闇的儀式」的卡名的怪獸無視召喚條件特殊召喚。\u000a②：此卡被對手破壞的場合可以發動。從手牌、牌組將1隻記載「光與闇的儀式」的卡名的儀式怪獸特殊召喚。'),'效果1','效果2','是否特殊召喚？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305046,'混沌禮帽','①：對手發動怪獸的效果、通常魔法、通常陷阱卡時可以發動。從牌組選卡名不同的3張魔法、陷阱卡，卡名當作「混沌禮帽」，當作通常怪獸（魔法使族、闇、等級8、攻/守0），和1隻記載「光與闇的儀式」的卡名的我方的主要怪獸區域的怪獸混合洗牌並裡側守備表示覆蓋。那之後，那個對手發動的效果變成「對手場上1隻裡側守備表示怪獸破壞」。','效果1','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305047,'三幻魔解放',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：從牌組將卡名不同的3隻「三幻魔」怪獸加入手牌。那之後，選2張我方的手牌捨棄。\u000a②：將不是在這個回合送去墓地的此卡從墓地除外可以發動。從牌組將1隻不能通常召喚的等級10的炎族、雷族、惡魔族怪獸加入手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305048,'三幻魔的失樂園',unistr('這個卡名的②效果1回合只能使用1次。\u000a①：1回合最多3次，我方主要階段可以發動。此卡以外的我方的手牌、場上（表側表示）的相同種類（怪獸、魔法、陷阱）的3張卡送去墓地。那之後，可以將我方的手牌、牌組、墓地、除外狀態的1隻「三幻魔」怪獸特殊召喚。此效果特殊召喚的怪獸不受對手發動的魔法、陷阱卡的效果影響。\u000a②：我方場上有原等級是10的「三幻魔」怪獸存在的場合可以發動。我方抽2張卡。'),'效果1','效果2','是否特殊召喚？','「三幻魔的失樂園」的效果特殊召喚','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305049,'三幻魔的霹靂',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：我方主要階段可以發動。從我方的手牌、牌組、墓地將2張「三幻魔的霹靂」在我方場上表側表示放置。那之後，可以向對手展示手牌的1隻等級10的「三幻魔」怪獸。展示的場合，隨後從牌組將1張「三幻魔的失樂園」在我方的場地區域表側表示放置。\u000a②：此卡在墓地存在的場合，對手結束階段可以發動。此卡加入手牌。'),'效果1','效果2','是否向對手展示？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305050,'天空城塞 庫龍',unistr('這個卡名的②③效果1回合各能使用1次。\u000a①：從手牌召喚、特殊召喚的我方場上的怪獸的攻擊力、守備力上升500。\u000a②：我方主要階段可以發動。在對手場上將1隻「機獸衍生物」（機械族、地、等級6、攻/守2000）特殊召喚，從牌組將1隻「雷盟」怪獸加入手牌。\u000a③：此卡在墓地存在的狀態，我方的「雷盟」卡片的效果將卡破壞的場合可以發動。此卡加入手牌。'),'','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305051,'雷盟-斷離粉碎',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：可以從以下效果選擇1個發動。\u000a●從牌組將1張「雷盟」永續陷阱卡在我方場上表側表示放置。\u000a●讓我方場上1隻雷族怪獸回到手牌，以場上1張卡為對象可以發動。那張卡破壞。\u000a②：此卡在墓地存在的狀態，我方的「雷盟」卡片的效果將卡破壞的場合可以發動。此卡加入手牌。'),'效果1','效果2','●放置永續陷阱卡','●破壞','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305052,'雷盟-先導雲步',unistr('這個卡名的①②③效果1回合各能使用1次。\u000a①：我方的「雷盟」卡片的效果將卡破壞的場合，以我方墓地1隻雷族怪獸為對象可以發動。那隻怪獸加入手牌。\u000a②：我方主要階段可以發動。從手牌將1隻雷族怪獸特殊召喚。那之後，此卡破壞。\u000a③：此卡在墓地存在的狀態，我方的「雷盟」卡片的效果將卡破壞的場合可以發動。此卡加入手牌。'),'效果1','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305053,'召喚魔術-「劍」',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：我方場上的怪獸作為融合素材，將1隻融合怪獸融合召喚。「召喚獸」融合怪獸融合召喚的場合，也能讓我方、對手的除外狀態的怪獸回到墓地作為融合素材。\u000a②：我方主要階段此卡在墓地存在的場合，以我方墓地1隻「阿萊斯特」怪獸或1張「召喚魔術」為對象可以發動。此卡回到牌組，對象卡片加入手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305054,'神靈劍 愛華斯',unistr('這個卡名的卡在1回合只能發動1張。\u000a①：可以從以下效果選擇1個發動。這個回合，我方除了用融合怪獸以外不能攻擊宣言。\u000a●從我方的牌組、墓地將1隻「法之神靈 愛華斯」特殊召喚。\u000a●從牌組選1隻「阿萊斯特」怪獸送去墓地或除外。\u000a●隨機確認3張對手的額外牌組的裡側的卡，挑選其中1張除外。'),'效果1','●從牌組、墓地特殊召喚','●從牌組選1隻「阿萊斯特」怪獸','●隨機確認對手的額外牌組','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305055,'絕境獄神域-皮萊亞',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：從我方的額外牌組、場上（表側表示）、墓地挑選「創獄神 涅路瓦」「壞獄神 朱庇特」「調獄神 朱諾拉」各1隻給雙方確認，這個回合，應對我方的「獄神」怪獸的效果的發動，對手不能發動效果。\u000a②：為了發動我方場上的「獄神」怪獸的效果而從牌組上方將卡除外的場合，可以將墓地的此卡除外作為代替。'),'效果1','是否將「絕境獄神域-皮萊亞」除外作為代替？','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305056,'無預幻的牧歌日常',unistr('這個卡名的①②效果1回合只有1次能使用其中1個。\u000a①：我方場上有「神藝」、「終刻」、「耀聖」卡片其中任何種類存在的場合可以發動。從手牌、牌組將1隻「無垢者 梅迪烏斯」特殊召喚。那次特殊召喚成功時對手不能發動卡的效果。\u000a②：將墓地的此卡除外，以我方墓地1隻融合、同步、超量怪獸為對象可以發動。那隻怪獸在連結怪獸指向的我方場上特殊召喚。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305057,'升階魔法-魅影騎士團鎮魂',unistr('這個卡名的卡在1回合只能發動1張。\u000a①：以我方的墓地、除外狀態的1隻「魅影騎士團」怪獸或「超量龍」怪獸為對象可以發動。那隻怪獸效果無效特殊召喚。那之後，適用以下效果。\u000a●挑選我方場上1隻闇屬性超量怪獸，將1隻階級比那隻怪獸高1階的「魅影騎士團」超量怪獸或「超量龍」超量怪獸重疊在挑選的怪獸上方，當作超量召喚從額外牌組特殊召喚。'),'效果1','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305058,'S-Force本源',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：我方的手牌、墓地、除外狀態的1隻「S-Force」怪獸特殊召喚。此效果特殊召喚的怪獸從場上離開的場合被除外。\u000a②：此卡在墓地存在的狀態，其他卡被除外的場合，將此卡除外可以發動。從牌組挑選「S-Force本源」以外的2張「S-Force」卡片，其中1張除外，另1張送去墓地。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305059,'童話動物摔倒倒',unistr('此卡發動的整回合中，我方除了「童話動物」怪獸以外不能特殊召喚。這個卡名的②效果1回合只能使用1次。\u000a①：從牌組將最多4隻「童話動物」怪獸加入手牌（同名卡最多1張）。那之後，變成這個回合的結束階段。\u000a②：將墓地的此卡除外，以「童話動物摔倒倒」以外的我方墓地2張「童話動物」卡片為對象可以發動。其中1張加入手牌，另1張回到牌組最下方。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305060,'靈力回復藥',unistr('這個卡名在規則上也當作「憑依」卡片。這個卡名的①②效果1回合只有1次能使用其中1個。\u000a①：從我方墓地的魔法使族怪獸以及魔法卡之中將任意數量除外可以發動。我方場上的全部怪獸的攻擊力上升除外數量×200，我方回復除外數量×400生命值。\u000a②：我方主要階段將墓地的此卡除外可以發動。從手牌將任意數量的魔法使族怪獸特殊召喚（相同屬性最多1隻）。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305061,'怠慢之壺','①：我方依照對手場上的卡片數量抽牌。抽2張以上的場合，隨後依照那個數量-1張，挑選我方的手牌以喜歡的順序回到牌組下方。此卡的發動後，直到回合結束時我方不能發動「怠慢之壺」。','效果1','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305062,'腐朽的祭儀要錄',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：從手牌、牌組將1張儀式魔法卡向對手展示，從牌組將1隻記載那個卡名的怪獸加入手牌。\u000a②：此卡在墓地存在的狀態，我方場上的表側表示的儀式怪獸因效果從場上離開的場合，如果我方場上沒有儀式怪獸以外的表側表示怪獸存在可以發動。此卡加入手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305063,'超電導閃輝 電漿爆破',unistr('這個卡名的卡在1回合只能發動1張。\u000a①：依照發動回合可以發動以下的效果。\u000a●我方回合：從牌組選1隻雷族、岩石族怪獸放置在牌組最上方。我方的場上或墓地有雷族、岩石族怪獸其中任何種類存在的場合，隨後可以將場上1張卡破壞。\u000a●對手回合：我方的場上、墓地、除外狀態的1隻雷族、岩石族怪獸加入手牌。這個回合已有怪獸被戰鬥、效果破壞的場合，加入手牌的怪獸也能從牌組挑選。'),'效果1','是否將1張卡破壞？','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305064,'夏',unistr('①：1回合1次，可以發動。依照沒有使用的對手的主要怪獸區域的數量，給此卡放置四季計數器。\u000a②：1回合1次，我方怪獸的攻擊宣言時可以發動。給予對手此卡的四季計數器的數量以及我方墓地的「春」的數量×400傷害。\u000a③：對手結束階段可以發動。從我方的手牌、牌組將可以放置四季計數器的1張場地魔法卡在我方場上表側表示放置（此卡的四季計數器轉移到那張卡）。那張卡的效果在這個回合不能發動。'),'效果1','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305065,'雙心切換',unistr('這個卡名的①效果1回合只能使用1次，①②效果不能在同一連鎖上發動。\u000a①：我方、對手回合可以發動。從牌組將1隻記載「光與闇的儀式」的卡名的怪獸加入手牌。那之後，選1張我方的手牌捨棄。\u000a②：對手發動卡的效果時，讓我方場上1隻等級7以上的怪獸回到手牌可以發動。從手牌將和回去的怪獸卡名不同的，1隻記載「光與闇的儀式」的卡名的怪獸無視召喚條件特殊召喚。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305066,'三幻魔合殺',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：從我方的手牌、墓地將1隻「三幻魔」怪獸守備表示特殊召喚。那之後，我方場上有原等級是10的「三幻魔」怪獸2隻以上存在的場合，可以將對手場上1張表側表示卡的效果無效並破壞。\u000a②：將墓地的此卡除外可以發動。我方的手牌、場上的怪獸作為融合素材，將1隻「幻魔」融合怪獸融合召喚。'),'效果1','效果2','是否將1張卡無效並破壞？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305067,'三幻魔的神淵',unistr('這個卡名的①③效果1回合各能使用1次。\u000a①：我方、對手的主要階段可以發動。從我方的手牌、牌組、墓地將2張「三幻魔的神淵」在我方場上表側表示放置。\u000a②：將包含此卡的我方場上3張表側表示的「三幻魔的神淵」送去墓地，以對手場上1隻表側表示怪獸為對象可以發動。那隻怪獸變成裡側守備表示。\u000a③：此卡在墓地存在的場合，對手結束階段可以發動。此卡回到牌組最下方。'),'效果1','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305068,'雷盟-回擊電衝',unistr('這個卡名的②③效果1回合各能使用1次。\u000a①：只要此卡在魔法與陷阱區域存在，我方場上的「雷盟」怪獸不會被對手的效果破壞。\u000a②：對手發動魔法卡的效果時，讓我方場上1隻「雷盟」怪獸回到手牌可以發動。那個效果無效並破壞。\u000a③：將墓地的此卡除外，以我方的場上、墓地1隻「雷盟」怪獸為對象可以發動。那隻怪獸回到手牌。'),'','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305069,'雷盟-交電夾擊',unistr('這個卡名的②③效果1回合各能使用1次。\u000a①：對手場上的怪獸的攻擊力、守備力下降我方場上的雷族怪獸數量×300。\u000a②：從我方的手牌、場上（表側表示）讓此卡以外的1張「雷盟」卡片回到牌組可以發動。從牌組將卡名和回去的卡不同的1隻雷族怪獸加入手牌。\u000a③：將墓地的此卡除外可以發動。從牌組將1張「雷盟」魔法卡或「天空城塞 庫龍」加入手牌。'),'','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305070,'魔法名-「新世界的開始」',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：從我方墓地將1隻「阿萊斯特」怪獸或融合怪獸除外可以發動。從額外牌組將1隻「召喚獸」怪獸無視召喚條件特殊召喚。此效果特殊召喚的怪獸在結束階段除外。\u000a②：此卡在墓地存在的狀態，怪獸被表側除外的場合，將此卡除外，以我方的除外狀態的1隻「召喚獸」怪獸為對象可以發動。那隻怪獸特殊召喚。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305071,'終末時刻的獄神影',unistr('這個卡名的卡在1回合只能發動1張。\u000a①：從我方的手牌、額外牌組（表側）、墓地將1隻「獄神」怪獸特殊召喚。那之後，依照我方場上的怪獸的種類（融合、同步、超量）的數量，以下效果各自可以適用。\u000a●1種以上：從對手牌組上方將3張卡裡側除外。\u000a●2種以上：對手場上1張卡裡側除外。\u000a●3種：對手的手牌隨機選1張裡側除外。'),'效果1','是否從牌組除外？','是否從場上除外？','是否從手牌除外？','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305072,'耀聖～繼唱的四重奏～',unistr('這個卡名的②效果1回合只能使用1次。\u000a①：我方的中央的主要怪獸區域的怪獸不能被對手的效果除外。\u000a②：從我方的手牌、場上將此卡以外的1張魔法、陷阱卡送去墓地，宣言1~4的任意等級可以發動。在我方場上將1隻持有宣言等級的「極花的大耀聖衍生物」（植物族、協調、炎、攻/守0）特殊召喚。只要此效果特殊召喚的衍生物存在，我方除了「耀聖」怪獸以外不能從額外牌組特殊召喚。'),'','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305073,'魅影騎士團 憤恨面紗',unistr('這個卡名的①②效果1回合各能使用1次。我方的場上或墓地有「魅影騎士團」怪獸存在的場合，此卡在覆蓋的回合也能發動。\u000a①：此卡發動後變成通常怪獸（戰士族、闇、等級3、攻0/守300），在怪獸區域守備表示特殊召喚（不當作陷阱卡）。那之後，可以將對手場上1隻攻擊表示怪獸變成守備表示。\u000a②：將墓地的此卡除外可以發動。進行1隻闇屬性超量怪獸的超量召喚。'),'適用「魅影騎士團 憤恨面紗」的效果來發動','效果2','是否改變表示形式？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305074,'S-Force理序世界',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：為了發動我方場上的「S-Force」怪獸的效果而將手牌除外的場合，可以從牌組將「S-Force理序世界」以外的1張「S-Force」卡片送去墓地作為代替。\u000a②：其他卡被除外的場合，以對手的場上、墓地1張卡為對象可以發動。那張卡除外。那之後，可以將我方場上1隻「S-Force」怪獸的位置向其他的我方的主要怪獸區域移動。'),'','效果2','是否要移動位置？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305075,'撲通通童話動物時間',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：以我方的場上、墓地1隻「童話動物」怪獸為對象可以發動。那隻怪獸回到手牌。那之後，可以將我方的手牌、場上的怪獸作為融合素材，將1隻獸族融合怪獸融合召喚。\u000a②：我方場上有「童話動物」超量怪獸存在的場合，將墓地的此卡除外可以發動。這個回合中，從額外牌組特殊召喚的我方場上的「童話動物」怪獸不受對手發動的效果影響。'),'效果1','效果2','是否融合召喚？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305076,'小丑戲幫『終演』',unistr('這個卡名的①②效果1回合只能各使用1次。\u000a①：上級召喚的怪獸在我方場上存在的場合，捨棄任意數量的手牌，以那個數量的場上的表側表示卡為對象可以發動。那些卡破壞。\u000a②：將墓地的此卡除外，將我方的手牌、場上1隻儀式、融合、同步、超量、靈擺、連結怪獸解放可以發動。從我方的牌組、墓地將1隻原本的等級、階級、連結的數值和那隻怪獸不同的「小丑戲幫」怪獸加入手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305077,'嗚呼的落穴','①：對手將怪獸特殊召喚過的回合，對手場上的怪獸的效果發動時可以發動。那隻發動效果的怪獸破壞。那之後，那隻怪獸存在的區域的前、後、相鄰的區域（怪獸區域、魔法與陷阱區域）有對手的卡存在的場合，將其全部破壞。','效果1','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305078,'車道管制',unistr('①：作為此卡的發動時的效果處理，可以將我方的除外狀態的1隻怪獸在我方的右端的主要怪獸區域特殊召喚。\u000a②：對手將要在自身的主要怪獸區域將怪獸召喚、特殊召喚的場合，必須從可以使用的最左側區域依序使用。'),'','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305079,'溯時的穿光',unistr('①：除了在這個回合召喚、反轉召喚、特殊召喚的怪獸以外，對手發動場上的怪獸的效果時可以發動。那個發動無效。那之後，除了在這個回合召喚、反轉召喚、特殊召喚的怪獸以外，可以將對手場上的表側表示怪獸全部裡側除外。\u000a②：覆蓋的此卡被對手的效果破壞的場合可以發動。從牌組將1張陷阱卡在我方場上覆蓋。\u000a\u000a※貫穿時空的溯光'),'','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305080,'護石庭園',unistr('這個卡名的②效果1回合只能使用1次。\u000a①：只要我方的魔法與陷阱區域有5張卡存在，雙方受到的戰鬥傷害變成一半，1回合1次，我方可以將1張永續陷阱卡在覆蓋的回合發動。\u000a②：我方、對手的準備階段可以發動。從牌組將卡名不同的5張永續陷阱卡向對手展示，對手從其中隨機選1張。我方將那1張卡在我方場上覆蓋，其餘回到牌組。'),'適用「護石庭園」的效果來發動','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305150,'機獸衍生物','由「天空城塞 庫龍」的效果特殊召喚。','','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101305172,'極花的大耀聖衍生物','由「耀聖～繼唱的四重奏～」的效果特殊召喚。只要此效果特殊召喚的衍生物存在，我方除了「耀聖」怪獸以外不能從額外牌組特殊召喚。','','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306001,'疾風的豹戰士',unistr('這個卡名的①效果1回合只能使用1次。\u000a①：我方、對手的主要階段，將場上的此卡以外的我方的手牌、場上1隻怪獸解放，可以從以下效果選擇1個發動。\u000a●除了「疾風的豹戰士」以外，從手牌、牌組將1隻記載「時間的黑魔術師」的卡名的怪獸特殊召喚。\u000a●從牌組將1張記載「時間的黑魔術師」的卡名的魔法、陷阱卡送去墓地。\u000a②：此卡只能在怪獸被解放的回合攻擊宣告。'),'效果1','','●特殊召喚','●從牌組送去墓地','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306002,'飛龍龍騎士',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡在手牌存在的場合，向對手展示此卡以外的手牌1張記載「時間的黑魔術師」的卡名的卡可以發動。此卡特殊召喚。\u000a②：此卡召喚、特殊召喚的場合可以發動。從牌組將最多2張記載「時間的黑魔術師」的卡名的魔法、陷阱卡加入手牌（同名卡最多1張）。那之後，選1張我方的手牌捨棄。\u000a③：此卡可以進行直接攻擊。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306003,'人造人-念力能量震懾者',unistr('這個卡名的②效果1回合只能使用1次。\u000a①：只要此卡在場上、墓地存在，卡名當作「人造人-念力震懾者」。\u000a②：此卡召喚、特殊召喚的場合可以發動。對手場上的陷阱卡全部破壞（裡側表示卡翻開確認）。那之後，此卡的攻擊力上升破壞數量×300。\u000a③：除了此卡以外，只要記載「時間的黑魔術師」的卡名的怪獸在我方的場上或墓地存在，對手不能發動陷阱卡的效果。'),'效果2','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306004,'大海的傳說-漁夫',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：對手發動場上的怪獸的效果的場合，或對手怪獸的攻擊宣告時，除了「大海的傳說-漁夫」以外，如果記載「時間的黑魔術師」的卡名的卡或「海」在場上存在可以發動。此卡從手牌特殊召喚。\u000a②：此卡特殊召喚的場合，以對手場上1隻怪獸為對象可以發動。那隻怪獸破壞。這個回合的結束階段，場上的此卡回到手牌。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306021,'D-HERO 死亡教條小子',unistr('此卡不能通常召喚。「D-HERO 死亡教條小子」只能1回合1次從我方墓地將戰士族或闇屬性的怪獸合計3隻除外，從手牌、墓地特殊召喚。\u000a①：這個方法將此卡特殊召喚的場合可以發動。下個準備階段，給予對手2000傷害。\u000a②：1回合1次，對手發動效果時可以發動。我方的手牌、場上、墓地的怪獸作為融合素材回到牌組，將1隻戰士族或闇屬性的融合怪獸融合召喚。'),'','效果1','效果2','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306022,'D-HERO 魔鬼統御小子',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：此卡召喚、特殊召喚的場合，以對手場上1隻怪獸為對象可以發動。那隻怪獸直到下個準備階段除外。\u000a②：從牌組將1隻「D-HERO」怪獸送去墓地可以發動。從我方的牌組、墓地將1張「幽獄的時鐘塔」或「幽獄的時鐘都市-黑暗城市」加入手牌。此效果的發動後，直到回合結束時我方除了闇屬性的「HERO」怪獸以外不能特殊召喚。'),'效果1','效果2','直到下個準備階段除外','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306023,'D-HERO 無懼從者',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：我方場上有「D-HERO」怪獸或場地魔法卡表側表示存在的場合可以發動。此卡從手牌特殊召喚。那之後，可以適用以下效果。\u000a●我方場上1張卡破壞，從牌組將1張「融合」加入手牌。\u000a②：我方將等級8的「D-HERO」怪獸特殊召喚的場合，將墓地的此卡除外，以對手場上1張卡為對象可以發動。那張卡回到牌組最上方。'),'效果1','效果2','是否破壞並檢索？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306036,'真紅眼超越黑龍',unistr('「真紅眼黑龍」+記載「時間的黑魔術師」的卡名的怪獸\u000a「真紅眼超越黑龍」只能1回合1次用融合召喚或以下方法特殊召喚。\u000a●「時間的黑魔術師」的效果將怪獸破壞的回合，將我方、對手的場上1隻表側表示怪獸解放，可以從額外牌組特殊召喚。\u000a①：此卡特殊召喚的場合可以發動。從我方的手牌、墓地將1隻等級8以下的怪獸特殊召喚。\u000a②：場上的此卡不受對手發動的魔法、怪獸的效果影響。'),'效果1','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306037,'D-HERO 無懼小子',unistr('等級5以上的「D-HERO」怪獸×2\u000a「D-HERO 無懼小子」只能1回合1次用融合召喚或以下方法特殊召喚。\u000a●將我方場上1隻「D-HERO 恐懼小子」解放，可以從額外牌組特殊召喚。\u000a①：此卡特殊召喚的場合可以發動。從牌組將「D-HERO」怪獸或記載那個卡名的卡合計2張加入手牌。\u000a②：此卡的攻擊力變成我方的場上、墓地的其他「D-HERO」怪獸的原攻擊力的合計數值。'),'效果1','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306052,'時間的黑魔術師',unistr('①：可以從以下效果選擇1個發動（這個卡名的以下效果1回合各能選擇1次）。\u000a●除了「時間的黑魔術師」以外，從牌組將1張記載「時間的黑魔術師」的卡名的卡加入手牌。這個回合的結束階段，從我方墓地將1張「時間的黑魔術師」加入手牌。\u000a●投擲1次硬幣，並猜正反面。如果猜對，對手場上的怪獸全部破壞，給予對手那些原攻擊力的合計數值一半的傷害。如果猜錯，我方場上的怪獸全部破壞。'),'效果1','●從牌組加入手牌','●投擲1次硬幣','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306053,'天使與魔鬼的骰子',unistr('①：擲2次骰子，這個回合中，以下效果各自適用。\u000a●我方場上的記載「時間的黑魔術師」的卡名的怪獸的攻擊力、守備力上升擲出點數的總和×200。\u000a●對手場上的怪獸的攻擊力、守備力下降擲出點數的總和×200。\u000a②：此卡在墓地存在的狀態，對手將怪獸召喚、特殊召喚的場合，將此卡除外，以其中1隻為對象可以發動。擲2次骰子，擲出點數的總和是6以上的場合，對象怪獸破壞。'),'效果1','效果2','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306054,'沉睡之羊 替罪山羊','①：在我方場上將最多4隻「替罪羊衍生物」（獸族、地、等級1、攻/守0）守備表示特殊召喚。對手場上有怪獸存在的場合，隨後可以從牌組將1隻「疾風的豹戰士」特殊召喚。這個回合，這個衍生物不能為了上級召喚而解放，我方除了融合怪獸以外不能從額外牌組特殊召喚。記載「時間的黑魔術師」的卡名的我方場上的卡被戰鬥、效果破壞的場合，可以將此效果特殊召喚的我方場上1隻衍生物破壞作為代替。','效果1','請選擇特殊召喚的數量','是否將「疾風的豹戰士」特殊召喚？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306062,'幽獄的時鐘都市-黑暗城市',unistr('這個卡名的①③效果1回合各能使用1次。\u000a①：此卡發動的回合的我方主要階段可以發動。從牌組將1隻「D-HERO」怪獸或1張記載那個卡名的卡加入手牌。\u000a②：每次我方將等級8以上的「D-HERO」怪獸特殊召喚發動。我方場上的全部戰士族怪獸的攻擊力上升300。\u000a③：此卡被破壞的場合可以發動。從牌組將1隻「D-HERO」怪獸當作「幽獄的時鐘塔」的效果特殊召喚。'),'效果1','效果2','效果3','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306070,'愚蠢的盜墓者',unistr('這個卡名的①②效果1回合各能使用1次。\u000a①：除了「愚蠢的盜墓者」以外，從牌組將1張記載「時間的黑魔術師」的卡名的卡送去墓地。那之後，可以將我方或對手的墓地1隻怪獸在我方場上特殊召喚。\u000a②：將墓地的此卡除外可以發動。以下的任何1張卡在我方場上覆蓋。\u000a●除了「愚蠢的盜墓者」以外，記載「時間的黑魔術師」卡名的我方墓地的魔法、陷阱卡。\u000a●對手墓地的魔法、陷阱卡'),'效果1','效果2','是否特殊召喚？','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306071,'大逆轉BOX',unistr('①：我方、對手的準備階段發動。擲1次骰子，最多到擲出點數的數量，給此卡放置計數器（最多6個）。\u000a②：對手怪獸攻擊的傷害計算時1次，或對手場上的怪獸的效果發動時，去除此卡的1個計數器，以其中1隻為對象可以發動。投擲1次硬幣，並猜正反面。如果猜對，從牌組將1隻記載「時間的黑魔術師」的卡名的怪獸特殊召喚，對象怪獸直到回合結束時攻擊力變成0，效果無效化。'),'效果1','效果2','請選擇要放置的計數器的數量','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306154,'替罪羊衍生物','由「沉睡之羊 替罪山羊」的效果特殊召喚。記載「時間的黑魔術師」的卡名的我方場上的卡被戰鬥、效果破壞的場合，可以將此卡破壞作為代替。','','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306254,'替罪羊衍生物','由「沉睡之羊 替罪山羊」的效果特殊召喚。記載「時間的黑魔術師」的卡名的我方場上的卡被戰鬥、效果破壞的場合，可以將此卡破壞作為代替。','','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306354,'替罪羊衍生物','由「沉睡之羊 替罪山羊」的效果特殊召喚。記載「時間的黑魔術師」的卡名的我方場上的卡被戰鬥、效果破壞的場合，可以將此卡破壞作為代替。','','','','','','','','','','','','','','','','');
INSERT INTO texts VALUES(101306454,'替罪羊衍生物','由「沉睡之羊 替罪山羊」的效果特殊召喚。記載「時間的黑魔術師」的卡名的我方場上的卡被戰鬥、效果破壞的場合，可以將此卡破壞作為代替。','','','','','','','','','','','','','','','','');
